import React from 'react';
import { BrowserRouter, Routes, Route, Navigate } from 'react-router-dom';
import { AuthProvider, useAuth } from './contexts/AuthContext';
import { SocketProvider } from './contexts/SocketContext';
import { Toaster } from './components/ui/toaster';
import LandingPage from './pages/LandingPage';
import Login from './pages/auth/Login';
import Register from './pages/auth/Register';
import ClientDashboard from './pages/client/ClientDashboard';
import CaseDetailPage from './pages/client/CaseDetail';
import AdvocateDashboard from './pages/advocate/AdvocateDashboard';
import AdvocateCaseDetail from './pages/advocate/AdvocateCaseDetail';
import ManagerDashboard from './pages/manager/ManagerDashboard';
import { Loader2 } from 'lucide-react';
import './App.css';

// Protected Route Component
const ProtectedRoute = ({ children, allowedRoles }) => {
  const { user, loading, isAuthenticated } = useAuth();

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <Loader2 className="w-8 h-8 animate-spin text-blue-600" />
      </div>
    );
  }

  if (!isAuthenticated) {
    return <Navigate to="/login" replace />;
  }

  if (allowedRoles && !allowedRoles.includes(user?.role)) {
    return <Navigate to="/" replace />;
  }

  return children;
};

// Home redirect based on authentication
const Home = () => {
  const { user, loading } = useAuth();

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <Loader2 className="w-8 h-8 animate-spin text-blue-600" />
      </div>
    );
  }

  // If user is logged in, redirect to their dashboard
  if (user) {
    if (user.role === 'client') {
      return <Navigate to="/client/dashboard" replace />;
    } else if (user.role === 'advocate') {
      return <Navigate to="/advocate/dashboard" replace />;
    } else if (user.role === 'platform_manager') {
      return <Navigate to="/manager/dashboard" replace />;
    }
  }

  // If not logged in, show landing page
  return <LandingPage />;
};

function App() {
  return (
    <AuthProvider>
      <SocketProvider>
      <BrowserRouter>
        <Routes>
          {/* Public Routes */}
          <Route path="/login" element={<Login />} />
          <Route path="/register" element={<Register />} />

          {/* Home / Dashboard Redirect */}
          <Route path="/" element={<Home />} />

          {/* Client Routes */}
          <Route
            path="/client/dashboard"
            element={
              <ProtectedRoute allowedRoles={['client']}>
                <ClientDashboard />
              </ProtectedRoute>
            }
          />
          <Route
            path="/client/cases/:caseId"
            element={
              <ProtectedRoute allowedRoles={['client']}>
                <CaseDetailPage />
              </ProtectedRoute>
            }
          />

          {/* Advocate Routes */}
          <Route
            path="/advocate/dashboard"
            element={
              <ProtectedRoute allowedRoles={['advocate']}>
                <AdvocateDashboard />
              </ProtectedRoute>
            }
          />
             <Route
            path="/advocate/cases/:caseId"
            element={
              <ProtectedRoute allowedRoles={['advocate']}>
                <AdvocateCaseDetail />
              </ProtectedRoute>
            }
          />


          {/* Manager Routes */}
          <Route
            path="/manager/dashboard"
            element={
              <ProtectedRoute allowedRoles={['platform_manager']}>
                <ManagerDashboard />
              </ProtectedRoute>
            }
          />

          {/* Catch all */}
          <Route path="*" element={<Navigate to="/" replace />} />
        </Routes>
      </BrowserRouter>
      <Toaster />
       </SocketProvider>
    </AuthProvider>
  );
}

export default App;
